import { useState } from "react";

const PLAYER = {
  EMPTY: 0,
  X: 1,
  O: 2,
};

const SYMBOLS = {
  [PLAYER.EMPTY]: "\xa0",
  [PLAYER.X]: "X",
  [PLAYER.O]: "O",
};

const WINNING_LINES = [
  [[0, 0], [0, 1], [0, 2]],
  [[1, 0], [1, 1], [1, 2]],
  [[2, 0], [2, 1], [2, 2]],
  [[0, 0], [1, 0], [2, 0]],
  [[0, 1], [1, 1], [2, 1]],
  [[0, 2], [1, 2], [2, 2]],
  [[0, 0], [1, 1], [2, 2]],
  [[0, 2], [1, 1], [2, 0]],
];

function emptyBoard() {
  return [
    [PLAYER.EMPTY, PLAYER.EMPTY, PLAYER.EMPTY],
    [PLAYER.EMPTY, PLAYER.EMPTY, PLAYER.EMPTY],
    [PLAYER.EMPTY, PLAYER.EMPTY, PLAYER.EMPTY],
  ];
}

function winner(board) {
  for (const line of WINNING_LINES) {
    const values = line.map(([r, c]) => board[r][c]);

    if (
      values[0] !== PLAYER.EMPTY &&
      values.every(value => value === values[0])
    ) {
      return values[0];
    }
  }

  return PLAYER.EMPTY;
}

export default function TicTacToe() {
  const [board, setBoard] = useState(emptyBoard());
  const [turn, setTurn] = useState(PLAYER.X);

  const winningPlayer = winner(board);

  function play(row, col) {
    if (winningPlayer !== PLAYER.EMPTY) return;
    if (board[row][col] !== PLAYER.EMPTY) return;

    const nextBoard = board.map(row => [...row]);
    nextBoard[row][col] = turn;

    setBoard(nextBoard);

    setTurn(
      turn === PLAYER.X ? PLAYER.O : PLAYER.X
    );
  }

  function reset() {
    setBoard(emptyBoard());
    setTurn(PLAYER.X);
  }

  return (
    <main>
      <h1>Tic Tac Toe</h1>

      <p>
        {winningPlayer !== PLAYER.EMPTY
          ? `${SYMBOLS[winningPlayer]} wins!`
          : `Turn: ${SYMBOLS[turn]}`}
      </p>

      <table style={{ fontFamily: "monospace" }}>
        <tbody>
          {board.map((row, r) => (
            <tr key={r}>
              {row.map((cell, c) => (
                <td
                  key={c}
                  onClick={() => play(r, c)}
                  style={{
                    border: "1px solid",
                    cursor: "pointer",
                  }}
                >
                  {SYMBOLS[cell]}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>

      <p>
        <button onClick={reset}>Reset</button>
      </p>
    </main>
  );
}
